import{_ as a,o as t,c as n,a3 as o}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"215. Examination Leave","description":"","frontmatter":{"title":"215. Examination Leave","eba":"Mental Health Services 2024-2028","topics":["leave","education-pd"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/education-pd/215-examination-leave.md","filePath":"ebas/mental-health/management-admin/education-pd/215-examination-leave.md"}'),i={name:"ebas/mental-health/management-admin/education-pd/215-examination-leave.md"};function r(s,e,l,d,m,h){return t(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_215-examination-leave" tabindex="-1">215. Examination Leave <a class="header-anchor" href="#_215-examination-leave" aria-label="Permalink to &quot;215. Examination Leave&quot;">​</a></h1><p><strong>215.1</strong> An Employee shall be granted leave on full pay in order to attend examinations necessary to obtain higher qualifications in such courses as are undertaken with the knowledge and approval of the Employer.</p><p><strong>215.2</strong> The amount of leave shall be such as to allow the Employee to proceed to and from the place of examinations and in addition allow three clear working days other than a Saturday or a Sunday for pre-examination study if this is so desired.</p><p><strong>215.3</strong> Any leave granted under the provisions of this clause shall be in addition to annual leave granted pursuant to <a href="/eba/ebas/mental-health/common-terms/leave/38D-annual-leave.html">clause 38D</a> (Annual Leave).</p><p><strong>215.4</strong> Leave with pay granted under the provisions of this clause shall not exceed six (6) clear working days per year. Chief Executive Officers and Deputy CEOs, other than those covered by the Victorian Public Entity Executive Remuneration Policy (PEER Policy), shall not be subject to this examination leave maxima.</p>',5)])])}const u=a(i,[["render",r]]);export{p as __pageData,u as default};
